/*
 * Embedded System Task Scheduler
 * 
 * A simple embedded OS demonstrating:
 * - Fixed priority scheduling (common in embedded/real-time systems)
 * - Memory-efficient task management
 * - Power management features
 * - Task states (READY, RUNNING, BLOCKED, SUSPENDED)
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

// Configuration for embedded system constraints
#define MAX_TASKS 8
#define STACK_SIZE 256 // Small stack for embedded constraints
#define TICK_RATE_MS 10 // System tick interval

// Task states
typedef enum {
 TASK_SUSPENDED = 0,
 TASK_READY,
 TASK_RUNNING,
 TASK_BLOCKED,
 TASK_WAITING
} TaskState;

// Task priority (lower number = higher priority in this implementation)
typedef enum {
 PRIORITY_CRITICAL = 0, // Hard real-time (e.g., safety systems)
 PRIORITY_HIGH = 1, // Time-critical
 PRIORITY_MEDIUM = 2, // Normal operations
 PRIORITY_LOW = 3, // Background tasks
 PRIORITY_IDLE = 4 // Lowest priority
} TaskPriority;

// Task Control Block (TCB) - lightweight structure for embedded systems
typedef struct {
 int task_id;
 char name[16];
 TaskState state;
 TaskPriority priority;
 void (*task_function)(void); // Function pointer to task code
 unsigned int stack[STACK_SIZE]; // Fixed-size stack
 unsigned int stack_pointer;
 unsigned int execution_time; // Time consumed in current slice
 unsigned int total_runtime; // Total CPU time used
 unsigned int deadline; // For real-time tasks
 bool periodic; // Is this a periodic task?
 unsigned int period_ms; // Period for periodic tasks
 unsigned int next_release; // Next release time for periodic tasks
} TaskControlBlock;

// System statistics
typedef struct {
 unsigned int system_time_ms;
 unsigned int context_switches;
 unsigned int cpu_utilization;
 unsigned int idle_ticks;
} SystemStats;

// Global variables
TaskControlBlock* current_task = NULL;
TaskControlBlock* task_list[MAX_TASKS];
int task_count = 0;
SystemStats stats = {0, 0, 0, 0};

// Function prototypes
void scheduler_init(void);
int task_create(const char* name, TaskPriority priority, void (*func)(void), bool periodic, unsigned int period_ms);
void scheduler_tick(void);
void task_delay(unsigned int ms);
void task_suspend(int task_id);
void task_resume(int task_id);
void power_save_mode(void);
void system_sleep(void);
void print_system_status(void);

// Simple priority-based scheduler
void scheduler_tick(void) {
 stats.system_time_ms += TICK_RATE_MS;

 // Find highest priority READY task
 TaskControlBlock* highest_priority = NULL;

 for (int i = 0; i < task_count; i++) {
 TaskControlBlock* task = task_list[i];

 // Skip non-ready tasks
 if (task->state != TASK_READY && task->state != TASK_RUNNING) {
 continue;
 }

 // Check if periodic task should be released
 if (task->periodic && stats.system_time_ms >= task->next_release) {
 task->state = TASK_READY;
 task->next_release += task->period_ms;
 }

 if (task->state == TASK_READY) {
 if (highest_priority == NULL || task->priority < highest_priority->priority) {
 highest_priority = task;
 }
 }
 }

 // Context switch if needed
 if (highest_priority != NULL && highest_priority != current_task) {
 // Save current task context
 if (current_task != NULL && current_task->state == TASK_RUNNING) {
 current_task->state = TASK_READY;
 }

 // Switch to new task
 current_task = highest_priority;
 current_task->state = TASK_RUNNING;
 stats.context_switches++;

 printf("[Tick %ums] → Context Switch: Running '%s' (Priority: %d)\n", 
 stats.system_time_ms, current_task->name, current_task->priority);
 }

 // Execute current task for one tick
 if (current_task != NULL) {
 current_task->execution_time += TICK_RATE_MS;
 current_task->total_runtime += TICK_RATE_MS;

 // Execute task function (simulated)
 printf("[Tick %ums] ● Running: '%s' | Exec Time: %ums\n", 
 stats.system_time_ms, current_task->name, current_task->execution_time);
 } else {
 stats.idle_ticks++;
 printf("[Tick %ums] ○ IDLE\n", stats.system_time_ms);
 }

 // Calculate CPU utilization
 unsigned int active_ticks = stats.system_time_ms - stats.idle_ticks;
 stats.cpu_utilization = (active_ticks * 100) / (stats.system_time_ms > 0 ? stats.system_time_ms : 1);
}

// Create a new task
int task_create(const char* name, TaskPriority priority, void (*func)(void), 
 bool periodic, unsigned int period_ms) {
 if (task_count >= MAX_TASKS) {
 printf("Error: Maximum number of tasks reached\n");
 return -1;
 }

 TaskControlBlock* new_task = (TaskControlBlock*)malloc(sizeof(TaskControlBlock));
 if (new_task == NULL) {
 printf("Error: Memory allocation failed\n");
 return -1;
 }

 new_task->task_id = task_count;
 strncpy(new_task->name, name, 15);
 new_task->name[15] = '\0';
 new_task->state = TASK_SUSPENDED;
 new_task->priority = priority;
 new_task->task_function = func;
 new_task->execution_time = 0;
 new_task->total_runtime = 0;
 new_task->deadline = 0;
 new_task->periodic = periodic;
 new_task->period_ms = period_ms;
 new_task->next_release = 0;

 task_list[task_count++] = new_task;

 printf("Created task: '%s' (Priority: %d, Periodic: %s, Period: %ums)\n",
 name, priority, periodic ? "Yes" : "No", period_ms);

 return new_task->task_id;
}

// Suspend a task
void task_suspend(int task_id) {
 if (task_id >= 0 && task_id < task_count) {
 task_list[task_id]->state = TASK_SUSPENDED;
 printf("Task '%s' suspended\n", task_list[task_id]->name);
 }
}

// Resume a task
void task_resume(int task_id) {
 if (task_id >= 0 && task_id < task_count) {
 task_list[task_id]->state = TASK_READY;
 printf("Task '%s' resumed\n", task_list[task_id]->name);
 }
}

// Power management: Enter low-power mode
void power_save_mode(void) {
 printf("⚡ Entering POWER SAVE mode (low power state)\n");
 printf(" - Reducing CPU frequency\n");
 printf(" - Disabling unused peripherals\n");
}

// System sleep
void system_sleep(void) {
 printf("💤 SYSTEM SLEEP: All tasks suspended, waiting for interrupt...\n");
}

// Print system status
void print_system_status(void) {
 printf("\n========================================\n");
 printf(" SYSTEM STATUS REPORT \n");
 printf("========================================\n");
 printf("System Time: %ums\n", stats.system_time_ms);
 printf("Context Switches: %u\n", stats.context_switches);
 printf("CPU Utilization: %u%%\n", stats.cpu_utilization);
 printf("Idle Ticks: %u\n", stats.idle_ticks);
 printf("Active Tasks: %d\n\n", task_count);

 printf("Task Details:\n");
 printf("----------------------------------------\n");
 printf("%-12s | %-8s | %-10s | %-8s\n", "Task Name", "Priority", "State", "Runtime");
 printf("----------------------------------------\n");

 for (int i = 0; i < task_count; i++) {
 TaskControlBlock* t = task_list[i];
 const char* state_str[] = {"SUSPENDED", "READY", "RUNNING", "BLOCKED", "WAITING"};
 printf("%-12s | %-8d | %-10s | %-8u\n", 
 t->name, t->priority, state_str[t->state], t->total_runtime);
 }
 printf("========================================\n\n");
}

// ============================================
// EXAMPLE TASKS (Simulated embedded functions)
// ============================================

void sensor_read_task(void) {
 // Simulates reading data from a temperature sensor
 printf(" [SENSOR] Reading temperature data...\n");
}

void display_update_task(void) {
 // Simulates updating an LCD display
 printf(" [DISPLAY] Updating LCD screen...\n");
}

void communication_task(void) {
 // Simulates wireless communication (e.g., IoT device)
 printf(" [COMM] Transmitting data...\n");
}

void data_logging_task(void) {
 // Simulates logging data to memory
 printf(" [LOG] Writing to flash memory...\n");
}

// Main function - Embedded System Demo
int main(void) {
 printf("\n");
 printf("╔═══════════════════════════════════════════╗\n");
 printf("║ EMBEDDED SYSTEM TASK SCHEDULER DEMO ║\n");
 printf("╚═══════════════════════════════════════════╝\n\n");

 // Create embedded tasks with different priorities
 // Priority 0 = Highest (Critical), Priority 4 = Lowest

 task_create("Safety_Monitor", PRIORITY_CRITICAL, sensor_read_task, true, 50);
 task_create("Display_Ctrl", PRIORITY_HIGH, display_update_task, true, 100);
 task_create("Wireless_Comms", PRIORITY_MEDIUM, communication_task, true, 200);
 task_create("Data_Logger", PRIORITY_LOW, data_logging_task, true, 500);

 printf("\n--- Starting Embedded System ---\n\n");

 // Simulate system running for several ticks
 for (int tick = 0; tick < 20; tick++) {
 scheduler_tick();
 }

 // Print final status
 print_system_status();

 // Demonstrate power management
 printf("--- Entering Low Power Mode ---\n");
 power_save_mode();

 return 0;
}
